import { FileFormat } from './file';
export type DownloadFileBatchRequest = {
    fileId: string;
    branchId?: string;
    versionId?: string;
    locale?: string;
}[];
export type DownloadFileBatchOptions = {
    timeout?: number;
};
export type BatchDownloadResult = {
    fileId: string;
    fileName: string;
    success: boolean;
    content?: string;
    contentType?: string;
    error?: string;
};
export type DownloadedFile = {
    id: string;
    branchId: string;
    fileId: string;
    versionId: string;
    locale?: string;
    fileName?: string;
    data: string;
    metadata: Record<string, any>;
    fileFormat: FileFormat;
};
export type DownloadFileBatchResult = {
    files: DownloadedFile[];
    count: number;
};
